import xml.etree.ElementTree as ET
from xml.parsers.expat import ExpatError

def parse_config_xml(file_path):
    try:
        # Parse XML with XXE protection
        parser = ET.XMLParser()
        parser.entity = {}
        parser.defaults = {}
        
        tree = ET.parse(file_path, parser)
        root = tree.getroot()
        
        settings = {}
        
        # Recursively parse all elements
        def parse_element(element):
            if len(element) == 0:  # Leaf element
                return element.text
            else:  # Parent element
                result = {}
                for child in element:
                    result[child.tag] = parse_element(child)
                return result
        
        # Process each setting
        for setting in root:
            if len(setting) == 0:
                settings[setting.tag] = setting.text
            else:
                settings[setting.tag] = parse_element(setting)
        
        return settings
        
    except (ET.ParseError, ExpatError, FileNotFoundError) as e:
        raise ValueError(f"Invalid XML configuration file: {str(e)}")